pub fn update(self: *Shark, camera_offset: f32) void {
    self.x += self.speed;
    self.x += camera_offset;

    //stop the shark at 4 screens ahead
    self.x = std.math.clamp(self.x, -2 * w4.screen_size, 4 * w4.screen_size);
}
pub fn draw(self: *const Shark) void {
    w4.DRAW_COLORS.* = 0x4020;
    w4.blit(&sprite, @intFromFloat(self.x), 92, width, height, sprite_flags);
}
